119→function renderClipboardIcon(entry: ClipboardEntry): ReactNode {
120→  if (entry.contentType === 'color') {
121→    return <ColorDot color={entry.content} />;
122→  }
123→  if (entry.contentType === 'image') {
124→    return <ImageIcon />;
125→  }
126→  return entry.sourceIcon;
127→}
