 81→        />
 82→      );
 83→    case 'link':
 84→      return (
 85→        <DetailMetadata.Link
 86→          key={index}
 87→          title={entry.title}
 88→          text={entry.text}
 89→          target={entry.target}
 90→        />
 91→      );
 92→    case 'tag-list':
 93→      return (
 94→        <DetailMetadata.TagList key={index} title={entry.title}>
 95→          {entry.tags.map(tag => (
 96→            <DetailMetadata.Tag
 97→              key={tag.text}
